#include <bits/stdc++.h>
#define int long long
using namespace std;
string s;
int dp[55][55];
signed main() {
	cin >> s;
	s = ' ' + s;
	memset( dp , 0x3f , sizeof( dp ) );
	for( int i = 1 ; i <= s.size() ; i++ ) {
		dp[i][i] = 1;
	}
	for( int len = 2 ; len <= s.size() ; len++ ) {
		for( int l = 1 ; l + len - 1 <= s.size() ; l++ ) {
			int r = l + len - 1;
			if( s[l] == s[r] ) {
				dp[l][r] = min( dp[l + 1][r] , dp[l][r - 1] );
			} else {
				for( int k = l ; k < r ; k++ ) {
				   dp[l][r] = min( dp[l][r] , dp[l][k] + dp[k + 1][r] );
				}
			}
		}
	}
	cout << dp[1][s.size()] - 1;
	return 0;
}
